function LxCityCtrl:InitRedPoints()
    local mainAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.Main)
    local mapTrans = mainAdapter:GetMapTrans()
    if IsNull(mapTrans) then return end

    local StaticRoot = mapTrans:Find("ShakeRoot/StaticRoot")
    if IsNull(StaticRoot) then return end

    self:RegisterRedPoint(FuncOpnIdConst.TimeMachineEntrance,StaticRoot:Find("NpcHeroCall/Red"))
end

function LxCityCtrl:RegisterRedPoint(funcId,trans)
    if IsNull(trans) then return end

    self._redpoints[funcId] = {
        redObj = trans.gameObject,
        funcId = funcId,
        isOpenFunc = function()
            return CtrlCenter.FuncOpen:IsFuncOpen(funcId, FuncOpenTipsEnum.Normal)
        end
    }
end

function LxCityCtrl:RefreshRedPoint()
    for k,v in pairs(self._redpoints) do
        local redNum = CtrlCenter.RedPoint:GetRedNum(k)
        ShowObject(v.redObj,redNum > 0)
    end
end


