function LxCityCtrl:ClearCityView()
    self:RemoveTouchList()
    self:RemoveEventHandlerList()

    self:StopTimer(_CityCtrlTimer.FrameRun)

    self._touchNpc = nil
    self._touchStart = false

    if self._cityView then
        --self._lastPos = self._cityView:GetMainRolePos()
        self._cityView:Dispose()
        self._cityView = nil
    end
end

function LxCityCtrl:InitCityView()

    self:InitRedPoints()
    self:InitNameLocks()
    self:InitTouchs()
    self:InitEvents()

    local isCreateRole = self._isCreateRole
    if ModuleCenter.Role:GetRenameCount() == 0 then
        ShowPanel(UiNames.RoleCreate)
        isCreateRole = true
    else
        self:OpenCityUi()
    end

    self._cityView = require("LApp.gameplay.city.view.LCityView"):new()
    self._cityView:Initialize()
    self._cityView:InitView(CityTypeEnum.city)
    --self._cityView:ShowMainRole(self._lastPos)
    self._mapRoot = self._cityView:GetMapRoot()

    self:StartTimer(_CityCtrlTimer.FrameRun, 0, true, -1, function() self:OnUpdate() end)

    if not isCreateRole then
        CtrlCenter.Guide:OnFirstEnterCity()
    end
    if not self._checkOfflineRevenue then
        CtrlCenter.Building:CheckOpenOfflineRevenuePanel()
        self._checkOfflineRevenue = true
    end
    gLxSdkImpl:CallMethod(SdkMethod.OnFirstEnterCity)

    self:RefreshRedPoint()
    self:RefreshFuncOpenState()
    FireEvent(EventNames.ON_ENTER_CITY)
    FireEvent(EventNames.ON_MAP_GUIDE_READY,{levelName = LevelNames.Main,functionType = FuncIds.City})
    CtrlCenter.Story:OnEnterCity()
end

