function LxCityCtrl:InitTouchs()
    self:AddTouch(TouchNames.On_TouchStart, self.OnTouchStart, self)
    self:AddTouch(TouchNames.On_TouchUp, self.OnTouchUp, self)
    self:AddTouch(TouchNames.On_Cancel, self.OnTouchCancel, self)

    self:AddTouch(TouchNames.On_SwipeStart, function(gesture)
        self:OnDragStart(gesture)
    end)

    self:AddTouch(TouchNames.On_SwipeEnd, function(gesture)
        self:OnDragEnd(gesture)
    end)

    self:AddTouch(TouchNames.On_Swipe, function(gesture)
        --if not self:CheckPlayerRoleIsIdle() then return end
        if self._touchNpc then self._touchNpc = nil end
        self:OnDrag(gesture)
    end)

    --- 收缩
    self:AddTouch(TouchNames.On_PinchIn,function(gesture)
        if not self._cityView then return end
        if self._cityView:IsCannotPinchScene() then return end
        if self._cityView:IsInStoryMode() then return end

        self._isPinch = true
        self:On_PinchIn(gesture)
        if(self:GetCityView())then
            self:GetCityView():ShowBuildHUD()
            self:GetCityView():HideBuildHUD()
            self:GetCityView():SetFollowNil()
        end

        CtrlCenter.Guide:CheckGuideTip()
    end)

    --- 放大
    self:AddTouch(TouchNames.On_PinchOut,function(gesture)
        if not self._cityView then return end
        if self._cityView:IsCannotPinchScene() then return end
        if self._cityView:IsInStoryMode() then return end

        self._isPinch = true
        self:On_PinchOut(gesture)
        if(self:GetCityView())then
            self:GetCityView():ShowBuildHUD()
            self:GetCityView():HideBuildHUD()
            self:GetCityView():SetFollowNil()
        end

        CtrlCenter.Guide:CheckGuideTip()
    end)

    self:AddTouch(TouchNames.On_PinchEnd,function(gesture)
        self._isPinch = false
    end)

    self:AddTouch(TouchNames.On_TouchUp2Fingers,function(gesture)
        self._isPinch = false
        if not self._cityView then return end
        self._cityView:CheckNeedAdjust()
    end)
end

function LxCityCtrl:OnTouchCancel()
    self._touchNpc = nil
    self._touchStart = false
end

---@param gesture Gesture
function LxCityCtrl:OnTouchStart(gesture)
    if not self._cityView then return end
    local position = gesture.position

    local go = nil
    local raycastHit = PJXUtil.TouchRaycastHit(position, gesture.fingerIndex)
    if raycastHit and raycastHit.collider then
        go = raycastHit.collider.gameObject
    end

    if go then
        self._touchStart = true
    end
    if self._cityView:IsInStoryMode() then
        return
    end
    if go and string.startswith(go.name, "JZ_") then
        if(self:CheckBuildCanClick(go) == false)then
            return
        end
        self._touchNpc = go
        go.transform.localScale = Vector3.New(0.98, 0.98, 0.98)
    end
    if(go and string.startswith(go.name,"Monster"))then
        self._touchNpc = go
    end
    if(go and  string.startswith(go.name,"People"))then
        self._touchNpc = go;
    end
end
--建筑是否能点击
function LxCityCtrl:CheckBuildCanClick(go)
    if(go and string.startswith(go.name,"JZ_"))then
        local building = self:GetCityView()._buildingMgr:GetBuildingByName(go.name)
        if(building == nil)then
            return false
        end
        local buildRefId = building._buildingRefId
        local show = self:GetCityView()._buildingMgr:GetBuildingShow(buildRefId)
        if(show == false)then
            return false
        end
    end

    return true
end
---@param gesture Gesture
function LxCityCtrl:OnTouchUp(gesture)
    if not self._touchStart then return end
    self._touchStart = false
    CtrlCenter.Guide:CheckGuideTip()
    local touchNpc = self._touchNpc
    if not touchNpc then return end

    local gos = PJXUtil.TouchHitObjects(gesture.position, gesture.fingerIndex)
    if gos and gos.Count > 0 then
        local count = gos.Count - 1
        local go
        for i=0, count do
            go = gos[i]
            if go and touchNpc == go then
                if LOG_INFO_ENABLED then
                    local info = LxUiHelper.GetUiPath(go.transform)
                    print("touch npc up "..go.name,info)
                end
                if(self:CheckBuildCanClick(go) == false)then
                    return
                end
                LxUiHelper.PlaySoundById(SoundNames.Common)
                self:OnClickNpc(go)
                if(go and  string.startswith(go.name,"JZ_"))then
                    touchNpc.transform.localScale = Vector3.one
                    go.transform.localScale = Vector3.one
                end

                self._touchNpc = nil
                break
            end
        end
    end
end

function LxCityCtrl:CheckTouchUp(gesture, isIgnoreUI)
    local go = nil
    local position = gesture.position
    local raycastHit
    if isIgnoreUI then
        raycastHit = PJXUtil.TouchRaycastHitIgnoreUI(position, gesture.fingerIndex)
        if raycastHit and raycastHit.collider then
            go = raycastHit.collider.gameObject
        end
    else
        raycastHit = PJXUtil.TouchRaycastHit(position, gesture.fingerIndex)
        if raycastHit and raycastHit.collider then
            go = raycastHit.collider.gameObject
        end
    end

    if go and go.name == self._mapRoot then
        self._cityView:OnTouchPos(go, raycastHit.point)
    end
    if go and self._touchNpc == go then
        self:OnClickNpc(go)
    end
    if self._touchNpc then
        self._touchNpc.transform.localScale = Vector3.one
        self._touchNpc = nil
    end
end

function LxCityCtrl:OnClickNpc(go)
    if(ModuleCenter.Story:IsNewbieRunning())then
        return
    end
    FireEvent(EventNames.LEVEL_CLICK_GO, go)
    if self._cityView then
        self._cityView:OnClickNpc(go)
    end

end
function LxCityCtrl:NewBieClickNpc(go)
