function LxCityCtrl:OnDragStart(gesture)

    if(ModuleCenter.Story:IsNewbieRunning())then
        return
    end
    self._isDragMapStart = false
    if not self._touchStart then return end
    if self._cityView and self._cityView:IsInStoryMode() then
        return
    end
    if(self:GetCityView())then
        self:GetCityView():ShowBuildHUD()
    end
    local go = PJXUtil.TouchHitObject(gesture.position,gesture.fingerIndex)
    if go and go == self._mapRoot or go == self._touchNpc then
        self._isDragMapStart = true
        self:OnDragMapStart(gesture.position)
    end
end
