---根据时间播放建筑动画
function LxCityCtrl:BuildingRestOrWork()
    local timeState = self:GetCurTimeState()
    if(timeState == 1 or timeState == 3)then
        --休息
        self:BuildingRest()
    else
        --工作
        self:BuildingWork()
    end
end
---获取时间状态
function LxCityCtrl:GetCurTimeState()
    local gameTime = CtrlCenter.People:GetPeopleTime()
    local gameHour , gameMin = CtrlCenter.People:GetGameHourAndMin(gameTime)
    local state = self:GetPeopleCurState(gameHour)
    return state
end
---获取游戏时间（时，分）
function LxCityCtrl:GetGameTime()
    local gameTime = CtrlCenter.People:GetPeopleTime()
    local gameHour , gameMin = CtrlCenter.People:GetGameHourAndMin(gameTime)
    return gameHour,gameMin
end
---@return 1:睡觉 2:工作 3:吃饭
function LxCityCtrl:GetPeopleCurState(gameHour)
    --do return 3 end
    if(gameHour > 23 or (gameHour >= 0 and gameHour <= 5))then
        return 1;--睡觉
    end
    if(gameHour > 5 and gameHour <= 9)then
        return 2;--工作
    end
    if(gameHour > 9 and gameHour <= 11)then
        return 3;--吃饭
    end
    if(gameHour > 11 and gameHour <= 16)then
        return 2;--工作
    end
    if(gameHour > 16 and gameHour <= 18)then
        return 3;--吃饭
    end
    if(gameHour > 18 and gameHour <= 23)then
        return 2;--工作
    end
end
