    if(self._cityView)then
        self._cityView:MoveToBuild(buildId, function()
            --打开升级界面
            if not dontOpenPanel then
                local buildLlv = ModuleCenter.Building:GetBuildingLvl(buildId)
                if buildLlv == 0 then
                    ShowPanel(UiNames.BuildCreate,{buildId = buildId,isResetCamera = true})
                else
                    local buildType = CtrlCenter.Building:GetBuildType(buildId)
                    if ResourceBuilding[buildType] then --资源建筑
                        ShowPanel(UiNames.BuildUpGrade,{buildId = buildId,isResetCamera = true})
                    else
                        ShowPanel(UiNames.BuildCreateTwo,{buildId = buildId,isResetCamera = true})
                    end
                end
            end
        end,isRet);
    end
end

function LxCityCtrl:MoveToBuildObjPanel(buildId, dontOpenPanel,delayTime) --打开建筑界面
    if(self._cityView)then
        local jumpFunc = function()
            self._cityView:MoveToBuild(buildId, function()
                --打开升级界面
                if not dontOpenPanel then
                    local buildLlv = ModuleCenter.Building:GetBuildingLvl(buildId)
                    if buildLlv == 0 then
                        ShowPanel(UiNames.BuildCreate,{buildId = buildId,isResetCamera = true})
                    else
                        local buildType = CtrlCenter.Building:GetBuildType(buildId)
                        local upGradeTime = CtrlCenter.Building:GetBuildUpGradeTime(buildId)
                        if upGradeTime > 0 then
                            if ResourceBuilding[buildType] then --资源建筑
                                ShowPanel(UiNames.BuildUpGrade,{buildId = buildId,isResetCamera = true})
                                ShowPanel(UiNames.BuildCreateTwo,{buildId = buildId})
                            else
                                ShowPanel(UiNames.BuildCreateTwo,{buildId = buildId,isResetCamera = true})
                            end
                            return
                        end
                        
                        if ResourceBuilding[buildType] then --资源建筑
                            ShowPanel(UiNames.BuildUpGrade,{buildId = buildId,isResetCamera = true})
                        else
                            if buildType == BuildingType.BingYingBu then
                                ShowPanel(UiNames.BarrackTrain, {buildId = buildId,soldierType = BarrackSoldierEnum.BuBing,isResetCamera =  true})
                            elseif buildType == BuildingType.BingYingQi then
                                ShowPanel(UiNames.BarrackTrain, {buildId = buildId,soldierType = BarrackSoldierEnum.QiBing,isResetCamera =  true})
                            elseif buildType == BuildingType.BingYingGong then
                                ShowPanel(UiNames.BarrackTrain, {buildId = buildId,soldierType = BarrackSoldierEnum.GongBing,isResetCamera =  true})
                            elseif buildType == BuildingType.Arena then
                                ShowPanel(UiNames.ArtsArena)
                            elseif buildType == BuildingType.ZhaoXianGe then
                                ShowPanel(UiNames.HeroSummons)
                            elseif buildType == BuildingType.YingHunDian then
                                ShowPanel(UiNames.HeroCorrelation)
                            elseif buildType == BuildingType.CangKu then
                                ShowPanel(UiNames.BuildWareHouse,{buildId = buildId,isResetCamera =  true})
                            elseif buildType == BuildingType.JunYiSuo then
                                ShowPanel(UiNames.MilitaryInstit,{buildId = buildId,isResetCamera =  true})
                            else
                                CtrlCenter.Building:OpenBuildUpLevelPanel(buildId,true)
                            end
                        end
                    end
                end
            end);
        end

        if delayTime then
            self:StartTimer(_CityCtrlTimer.OpenBuild, 0.6, true, 1, function()
                jumpFunc()
            end)
        else
            jumpFunc()
        end
    end
end
